#include "ai_factory/cuda/cir_plus_plus/zero_coupon_bonds.cuh"
#include "ai_factory/common/fixed_income/nelson_siegel.hpp"
#include "ai_factory/cuda/common/runtime.cuh"
namespace ai_factory::cuda {namespace{struct Tag{};__global__ void kernel(const CirPlusPlusZeroCouponBondRow*r,std::size_t n,MonteCarloOutput*o){const auto i=static_cast<std::size_t>(blockIdx.x)*blockDim.x+threadIdx.x;if(i<n){const auto x=r[i];o[i]={x.product.notional*fixed_income::nelson_siegel_discount(x.product.maturity,x.curve.beta0,x.curve.beta1,x.curve.beta2,x.curve.tau),0.0};}}}
void price_cir_plus_plus_zero_coupon_bond_cuda(const CirPlusPlusZeroCouponBondRow*h,std::size_t n,MonteCarloOutput*out,CudaTiming*t){auto&w=detail::reusable_cuda_workspace<Tag,2>();auto*r=w.buffer<CirPlusPlusZeroCouponBondRow>(0,n,"CIR++ rows");auto*o=w.buffer<MonteCarloOutput>(1,n,"CIR++ outputs");detail::check_cuda(cudaMemcpy(r,h,n*sizeof(*h),cudaMemcpyHostToDevice),"copy CIR++ rows");detail::check_cuda(cudaEventRecord(w.start_event()),"start");kernel<<<static_cast<unsigned>((n+255)/256),256>>>(r,n,o);detail::check_cuda(cudaGetLastError(),"CIR++ zero coupon kernel");detail::check_cuda(cudaEventRecord(w.stop_event()),"stop");detail::check_cuda(cudaEventSynchronize(w.stop_event()),"sync");float ms=0;detail::check_cuda(cudaEventElapsedTime(&ms,w.start_event(),w.stop_event()),"elapsed");detail::check_cuda(cudaMemcpy(out,o,n*sizeof(*out),cudaMemcpyDeviceToHost),"copy outputs");if(t){t->simulation_ms=ms;t->total_ms=ms;}}
}
